import { query, getRequestEvent } from '$app/server';
import { z } from 'zod';
import { createServerApi } from '$lib/server/api';
import { contentQuerySchema } from '@codex/validation';  // Reuse existing schema!

// List content with pagination/filtering
// Uses existing schema from @codex/validation (Zod v3, Standard Schema compatible)
export const listContent = query(
  contentQuerySchema.optional(),
  async (params) => {
    const { platform, cookies } = getRequestEvent();
    const api = createServerApi(platform, cookies);

    const searchParams = new URLSearchParams();
    if (params?.page) searchParams.set('page', String(params.page));
    if (params?.limit) searchParams.set('limit', String(params.limit));
    if (params?.status) searchParams.set('status', params.status);
    if (params?.organizationId) searchParams.set('organizationId', params.organizationId);

    return api.content.list(searchParams);
  }
);

// Get single content by ID
export const getContent = query(z.string().uuid(), async (id) => {
  const { platform, cookies } = getRequestEvent();
  const api = createServerApi(platform, cookies);
  return api.content.get(id);
});

// Get content by slug (public, for SEO)
export const getContentBySlug = query(
  z.object({ orgSlug: z.string(), contentSlug: z.string() }),
  async ({ orgSlug, contentSlug }) => {
    const { platform, cookies } = getRequestEvent();
    const api = createServerApi(platform, cookies);
    // Assumes endpoint exists or compose from org + content
    return api.content.getBySlug?.(orgSlug, contentSlug);
  }
);
```

