# Phase 3.3: Library Collection with Optimistic Updates

Create the library collection with optimistic playback progress updates.

## Files to Create

### `apps/web/src/lib/collections/library.ts`

```typescript
import { createCollection } from '@tanstack/svelte-db';
import { queryCollectionOptions } from '@tanstack/query-db-collection';
import { getUserLibrary, savePlaybackProgress } from '$lib/remote/library.remote';
import { queryClient } from './index';
import type { UserLibraryResponse } from '@codex/shared-types';

type LibraryItem = UserLibraryResponse['items'][number];

/**
 * Library Collection
 * 
 * User's content library (purchased + free content).
 * Supports optimistic progress updates.
 */
export const libraryCollection = createCollection(
  queryCollectionOptions<LibraryItem>({
    id: 'library',
    queryKey: ['library'],

    // Load via remote function
    queryFn: async () => {
      const result = await getUserLibrary();
      return result.items;
    },

    queryClient,
    getKey: (item) => item.content.id,

    /**
     * Handle optimistic updates
     * Called when collection.update() is used
     */
    onUpdate: async ({ transaction }) => {
      const { key, modified, changes } = transaction.mutations[0];

      // Only sync progress changes to server
      if (changes.progress) {
        try {
          await savePlaybackProgress({
            contentId: key as string,
            positionSeconds: modified.progress.positionSeconds,
            durationSeconds: modified.progress.durationSeconds,
          });
        } catch (error) {
          // Transaction automatically rolls back on error
          console.error('Failed to save progress:', error);
          throw error;
        }
      }
    },
  })
);

/**
 * Helper to update playback progress
 * Optimistic update - UI updates immediately, syncs in background
 */
export function updateProgress(
  contentId: string,
  positionSeconds: number,
  durationSeconds: number
) {
  libraryCollection.update(contentId, (draft) => {
    draft.progress = {
      positionSeconds,
      durationSeconds,
      completed: durationSeconds > 0 && (positionSeconds / durationSeconds) > 0.9,
      updatedAt: new Date().toISOString(),
    };
  });
}
```

