    const loggedData = JSON.parse(consoleSpy.info.mock.calls[0]?.[0] as string);
    expect(loggedData.requestId).toBe('req-abc-123');
  });

  it('should not include requestId when not set', () => {
    const obs = new ObservabilityClient('test-service');
    obs.info('test message');

    const loggedData = JSON.parse(consoleSpy.info.mock.calls[0]?.[0] as string);
    expect(loggedData.requestId).toBeUndefined();
  });

  it('should include requestId in all log levels', () => {
    const obs = new ObservabilityClient('test-service');
    obs.setRequestId('req-xyz-789');

    obs.info('info msg');
    obs.warn('warn msg');
    obs.error('error msg');

    for (const level of ['info', 'warn', 'error'] as const) {
      const loggedData = JSON.parse(consoleSpy[level].mock.calls[0]?.[0] as string);
      expect(loggedData.requestId).toBe('req-xyz-789');
    }
  });

  it('should include requestId in trackError output', () => {
    const obs = new ObservabilityClient('test-service');
    obs.setRequestId('req-err-456');
    obs.trackError(new Error('boom'), { url: '/fail' });

    const loggedData = JSON.parse(consoleSpy.error.mock.calls[0]?.[0] as string);
    expect(loggedData.requestId).toBe('req-err-456');
  });

  it('should include requestId in trackRequest output', () => {
    const obs = new ObservabilityClient('test-service');
    obs.setRequestId('req-track-001');
    obs.trackRequest({ url: '/api/test', method: 'GET', duration: 50, status: 200 });

    const loggedData = JSON.parse(consoleSpy.info.mock.calls[0]?.[0] as string);
    expect(loggedData.requestId).toBe('req-track-001');
  });
});
