import { fail } from '@sveltejs/kit';
import { serverApiUrl } from '$lib/server/api';
import { HEADERS, MIME_TYPES } from '@codex/constants';
import type { Actions } from './$types';

export const actions: Actions = {
  default: async ({ request, platform }) => {
    const data = await request.formData();
    const email = data.get('email') as string;

    // Validate
    if (!email || !email.includes('@')) {
      return fail(400, { email, errors: { email: 'Please enter a valid email address' } });
    }

    try {
      const authUrl = serverApiUrl(platform, 'auth');
      await fetch(authUrl + '/api/auth/email/send-reset-password-email', {
        method: 'POST',
        headers: { [HEADERS.CONTENT_TYPE]: MIME_TYPES.APPLICATION.JSON },
        body: JSON.stringify({ email }),
      });
    } catch {
      // Intentionally swallow errors — do not reveal if email exists
    }

    // Always show success
    return { success: true, email };
  },
};

