    <div class="success-banner" role="status">Profile updated successfully!</div>
  {/if}
  {#if form?.error}
    <div class="error-banner" role="alert">{form.error}</div>
  {/if}

  <div class="form-group">
    <label for="display-name">Display Name</label>
    <input type="text" id="display-name" name="name"
      value={form?.name ?? data.user?.name ?? ''}
      placeholder="Your display name" />
    {#if form?.errors?.name}
      <span class="field-error">{form.errors.name}</span>
    {/if}
  </div>

  <div class="form-group">
    <label for="email">Email</label>
    <input type="email" id="email" value={data.user?.email ?? ''} disabled />
    <p class="form-help">Email cannot be changed here. Contact support.</p>
  </div>

  <Button type="submit" {loading}>Save Changes</Button>
</form>

